import torch
import torch.nn as nn

# Test 1: torch.sum(x * x)
class TestNorm(nn.Module):
    def forward(self, z_hat):
        batch_size = z_hat.size(0)
        z_flat = z_hat.reshape(batch_size, -1).float()
        z_norm = torch.sqrt(torch.sum(z_flat * z_flat, dim=1, keepdim=True))
        return z_norm

model = TestNorm().eval()
dummy = torch.randn(2, 32, 8, 8)
try:
    torch.onnx.export(model, dummy, '/tmp/test_norm.onnx', opset_version=12)
    print('norm test (sum x*x): OK')
except Exception as e:
    print(f'norm test (sum x*x) failed: {e}')

# Test 2: Check if torch.sqrt triggers anything
class TestSqrt(nn.Module):
    def forward(self, x):
        return torch.sqrt(x + 1.0)

model2 = TestSqrt().eval()
dummy2 = torch.randn(2, 3, 32, 32)
try:
    torch.onnx.export(model2, dummy2, '/tmp/test_sqrt.onnx', opset_version=12)
    print('sqrt test: OK')
except Exception as e:
    print(f'sqrt test failed: {e}')

# Test 3: Check ECA's adaptive_avg_pool2d
class TestPool(nn.Module):
    def __init__(self):
        super().__init__()
        self.pool = nn.AdaptiveAvgPool2d(1)
    def forward(self, x):
        return self.pool(x)

model3 = TestPool().eval()
dummy3 = torch.randn(2, 32, 8, 8)
try:
    torch.onnx.export(model3, dummy3, '/tmp/test_pool.onnx', opset_version=12)
    print('pool test: OK')
except Exception as e:
    print(f'pool test failed: {e}')

# Test 4: Check torch.bmm (used in original norm layer)
class TestBMM(nn.Module):
    def forward(self, x, y):
        return torch.bmm(x, y)

model4 = TestBMM().eval()
dummy4a = torch.randn(2, 1, 32)
dummy4b = torch.randn(2, 32, 1)
try:
    torch.onnx.export(model4, (dummy4a, dummy4b), '/tmp/test_bmm.onnx', opset_version=12)
    print('bmm test: OK')
except Exception as e:
    print(f'bmm test failed: {e}')
